            {[{lbl:"HIT TP",pct:st.tot>0?(st.tp/st.tot)*100:0,col:G},{lbl:"HIT SL",pct:st.tot>0?(st.sl/st.tot)*100:0,col:R}].map(b=>(<div key={b.lbl} style={{marginBottom:8}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}><span style={{fontSize:13,color:b.col,fontWeight:700}}>{b.lbl}</span><span style={{fontSize:13,color:b.col,fontWeight:700}}>{b.pct.toFixed(1)}%</span></div><div style={{height:5,background:BORDER,borderRadius:3,overflow:"hidden"}}><div style={{height:"100%",width:`${b.pct}%`,background:b.col,borderRadius:3,transition:"width .5s"}}/></div></div>))}
