                <button key={f} className="btn" onClick={()=>setFilterDir(f)} style={{background:filterDir===f?(f==="BUY"?`${G}18`:f==="SELL"?`${R}18`:"#20242c"):"transparent",border:`1px solid ${filterDir===f?(f==="BUY"?G+"44":f==="SELL"?R+"44":BORDER):BORDER}`,color:filterDir===f?(f==="BUY"?G:f==="SELL"?R:TEXT):DIM,padding:"6px 14px",borderRadius:8,fontSize:11,fontWeight:600}}>{l}</button>
